import{_ as t,o as a,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"8. No Extra Claims","description":"","frontmatter":{"title":"8. No Extra Claims","eba":"Medical Specialists 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/preliminary/8-no-extra-claims.md","filePath":"ebas/medical-specialists/preliminary/8-no-extra-claims.md"}'),s={name:"ebas/medical-specialists/preliminary/8-no-extra-claims.md"};function r(n,e,c,l,m,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_8-no-extra-claims" tabindex="-1">8. No Extra Claims <a class="header-anchor" href="#_8-no-extra-claims" aria-label="Permalink to &quot;8. No Extra Claims&quot;">​</a></h1><p><strong>(a)</strong> Subject to subclause 8(b), until the nominal expiry date of this Agreement, a Health Service, Doctor or Doctor organisation covered by this Agreement must not pursue any extra claims.</p><p><strong>(b)</strong> Subclause (a) does not limit:</p><p><strong>(i)</strong> the resolution of an issue, that is not also a collective issue affecting more than one Doctor, arising under an individual Doctor&#39;s contract of employment by the Health Service and the Doctor in a manner consistent with subclause 31.11(a); or</p><p><strong>(ii)</strong> the Health Service’s capacity to introduce change at the workplace, subject to meeting its requirements to consult; or</p><p><strong>(iii)</strong> a Health Service and Doctor&#39;s ability to make an individual flexibility arrangement consistent with <a href="/eba/ebas/medical-specialists/consultation-disputes/15-individual-flexibility-arrangements.html">clause 15</a> below.</p><p><strong>(c)</strong> Issues arising under an individual Doctor&#39;s contract of employment must not be used to circumvent the operation of subclause (a).</p><p><strong>(d)</strong> The Health Services agree to commence discussions with the Association no later than six months prior to the nominal expiry date of this Agreement. Provided that any claim made by a person covered by this Agreement during that six-month period is not supported by industrial action, subclause (a) does not prevent a person covered by this Agreement from making a claim during the six-month period (or such earlier period as may be agreed) prior to the nominal expiry date of this Agreement.</p><p>FLEXIBLE WORKING ARRANGEMENTS</p><p>Plain language terms: no further claims.</p>',10)])])}const h=t(s,[["render",r]]);export{u as __pageData,h as default};
